// Edge-Cloud Data Processing Decision
CONST THRESHOLD_LATENCY = 100 // milliseconds
CONST THRESHOLD_DATA_SIZE = 1 // MB

FUNCTION process_iot_data(data, device_capabilities):
 data_size = calculate_size(data)
 required_analysis = determine_analysis_complexity(data)

 // Decide: Edge or Cloud?
 IF device_capabilities.can_process_locally AND 
 required_analysis.complexity <= device_capabilities.capacity AND
 data_size <= THRESHOLD_DATA_SIZE:
 // Process at edge for low latency
 result = process_locally(data)
 RETURN {location: "edge", result: result}

 ELSE IF network_available():
 // Send to cloud for complex processing
 result = send_to_cloud(data)
 RETURN {location: "cloud", result: result}

 ELSE:
 // Store locally for later processing
 store_local(data)
 RETURN {location: "queued", result: null}

